import { FormMode } from '../../../../../components/form';
import type { VoucherStatus } from '../../../../../services/kt/models';
import { createField, setFieldValue, type IField } from '../../../../form-shared';
import { defaultJournalEntryHeader, JOURNAL_ENTRY_DISPLAY_ONLY_KEYS, type JournalEntryHeaderKey } from '../types/journalEntryHeader.types';
import { emptyJournalEntryLine, type JournalEntryLineModel } from '../types/journalEntryLine.types';
import {
  initJournalLineFields,
  newLineId,
  type JournalEntryLineFieldState,
} from './journalEntryFieldHelpers';
import { setFieldValue as setFv } from '../../../../form-shared';

export interface JournalEntryFormMeta {
  status: VoucherStatus;
}

export interface JournalEntryFormReducerState {
  header: Record<JournalEntryHeaderKey, IField<string>>;
  lines: JournalEntryLineFieldState[];
  meta: JournalEntryFormMeta;
  formMode: FormMode;
}

export type JournalEntryFormAction =
  | { type: 'SET_HEADER'; key: JournalEntryHeaderKey; value: string }
  | { type: 'SET_LINE'; lineId: string; key: keyof JournalEntryLineModel; value: string | number }
  | { type: 'ADD_LINE' }
  | { type: 'REMOVE_LINE'; index: number }
  | { type: 'INIT'; header: Record<JournalEntryHeaderKey, IField<string>>; lines: JournalEntryLineFieldState[]; status: VoucherStatus }
  | { type: 'SET_META'; patch: Partial<JournalEntryFormMeta> }
  | { type: 'SET_FORM_MODE'; formMode: FormMode }
  | { type: 'RESET' };

function initHeader() {
  const model = defaultJournalEntryHeader();
  const out = {} as Record<JournalEntryHeaderKey, IField<string>>;
  (Object.keys(model) as JournalEntryHeaderKey[]).forEach(key => {
    out[key] = createField(model[key], { displayOnly: JOURNAL_ENTRY_DISPLAY_ONLY_KEYS.includes(key) });
  });
  return out;
}

export function createInitialJournalEntryFormState(): JournalEntryFormReducerState {
  return {
    header: initHeader(),
    lines: [initJournalLineFields(emptyJournalEntryLine(), newLineId())],
    meta: { status: 'Draft' },
    formMode: FormMode.Edit,
  };
}

export function journalEntryFormReducer(
  state: JournalEntryFormReducerState,
  action: JournalEntryFormAction,
): JournalEntryFormReducerState {
  switch (action.type) {
    case 'SET_HEADER': {
      const displayOnly = JOURNAL_ENTRY_DISPLAY_ONLY_KEYS.includes(action.key);
      return {
        ...state,
        header: {
          ...state.header,
          [action.key]: setFieldValue(state.header[action.key], action.value, displayOnly),
        },
      };
    }
    case 'SET_LINE': {
      const idx = state.lines.findIndex(l => l.lineId === action.lineId);
      if (idx < 0) return state;
      const line = state.lines[idx];
      const field = line.fields[action.key];
      const nextLines = [...state.lines];
      nextLines[idx] = {
        ...line,
        fields: { ...line.fields, [action.key]: setFv(field, action.value) },
      };
      return { ...state, lines: nextLines };
    }
    case 'ADD_LINE':
      return { ...state, lines: [...state.lines, initJournalLineFields(emptyJournalEntryLine(), newLineId())] };
    case 'REMOVE_LINE':
      if (state.lines.length <= 1) return state;
      return { ...state, lines: state.lines.filter((_, i) => i !== action.index) };
    case 'INIT':
      return { ...state, header: action.header, lines: action.lines, meta: { status: action.status } };
    case 'SET_META':
      return { ...state, meta: { ...state.meta, ...action.patch } };
    case 'SET_FORM_MODE':
      return { ...state, formMode: action.formMode };
    case 'RESET':
      return createInitialJournalEntryFormState();
    default:
      return state;
  }
}
