export interface JournalEntryHeaderModel {
  entryDate: string;
  code: string;
  description: string;
  referenceNo: string;
  referenceCustomerName: string;
  processingLevel: string;
}

export type JournalEntryHeaderKey = keyof JournalEntryHeaderModel;

export const defaultJournalEntryHeader = (): JournalEntryHeaderModel => ({
  entryDate: new Date().toISOString().slice(0, 10),
  code: '',
  description: '',
  referenceNo: '',
  referenceCustomerName: '',
  processingLevel: '',
});

export const JOURNAL_ENTRY_DISPLAY_ONLY_KEYS: JournalEntryHeaderKey[] = ['code', 'referenceCustomerName'];
